from collections import Counter

class Solution:
    def countSubarrays(self, nums, k, m):
        # true brute force: recount every subarray's frequency table from scratch with
        # Counter, independent of the incremental deficient-count bookkeeping below.
        n = len(nums)
        total = 0
        for i in range(n):
            for j in range(i, n):
                c = Counter(nums[i:j+1])
                if len(c) == k and all(v >= m for v in c.values()):
                    total += 1
                elif len(c) > k:
                    break
        return total

