class Solution:
    def countSubarrays(self, nums, k, m):
        n = len(nums)
        total = 0
        for i in range(n):
            freq = {}
            distinct = 0
            deficient = 0
            for j in range(i, n):
                v = nums[j]
                c = freq.get(v, 0)
                if c == 0:
                    distinct += 1
                    deficient += 1
                freq[v] = c + 1
                if c + 1 == m:
                    deficient -= 1
                if distinct > k:
                    break
                if distinct == k and deficient == 0:
                    total += 1
        return total

