var countSubarrays = function(nums, k, m) {
    const n = nums.length;
    let total = 0;
    for (let i = 0; i < n; i++) {
        const freq = new Map();
        let distinct = 0;
        let deficient = 0;
        for (let j = i; j < n; j++) {
            const v = nums[j];
            const c = freq.get(v) || 0;
            if (c === 0) {
                distinct++;
                deficient++;
            }
            freq.set(v, c + 1);
            if (c + 1 === m) deficient--;
            if (distinct > k) break;
            if (distinct === k && deficient === 0) total++;
        }
    }
    return total;
};
